:host {
    display: block;
    color: var(--app-body-color, var(--mat-sys-on-surface));
}

.account-dialog__hero {
    margin: 0;
    padding: 28px 28px 24px;
    display: grid;
    gap: 22px;
    background:
        radial-gradient(
            circle at top right,
            rgba(99, 102, 241, 0.22),
            transparent 34%
        ),
        radial-gradient(
            circle at bottom left,
            rgba(34, 211, 238, 0.12),
            transparent 32%
        ),
        linear-gradient(
            180deg,
            rgba(255, 255, 255, 0.06),
            rgba(255, 255, 255, 0)
        ),
        var(--app-widget-header-bg, var(--mat-sys-surface-container-high));
    border-bottom: 1px solid var(--app-separator);
}

.account-dialog__hero-copy {
    display: grid;
    gap: 14px;
}

.account-dialog__eyebrow {
    display: inline-flex;
    align-items: center;
    gap: 10px;
    margin: 0;
    color: var(--app-eyebrow-color, var(--mat-sys-on-surface-variant));
    font-size: 0.78rem;
    font-weight: 700;
    letter-spacing: 0.12em;
    text-transform: uppercase;
}

.account-dialog__eyebrow-mark {
    width: 10px;
    height: 10px;
    border-radius: 999px;
    background: var(--app-provider-xtream, var(--mat-sys-primary));
    box-shadow: 0 0 0 6px rgba(99, 102, 241, 0.14);
}

.account-dialog__eyebrow-divider {
    width: 4px;
    height: 4px;
    border-radius: 999px;
    background: currentColor;
    opacity: 0.5;
}

.account-dialog__headline-row {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 16px;
}

.account-dialog__title {
    margin: 0;
    font-family:
        'Crimson Pro',
        'DM Sans',
        serif;
    font-size: clamp(2rem, 4vw, 2.8rem);
    line-height: 0.96;
    font-weight: 600;
    letter-spacing: -0.04em;
    color: var(--app-heading-color, var(--mat-sys-on-surface));
}

.account-dialog__subtitle {
    margin: 8px 0 0;
    color: var(--app-muted-color, var(--mat-sys-on-surface-variant));
    font-size: 0.98rem;
}

.account-dialog__status-cluster {
    display: flex;
    flex-wrap: wrap;
    justify-content: flex-end;
    gap: 8px;
}

.account-dialog__status-pill {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: 34px;
    padding: 0 14px;
    border-radius: 999px;
    border: 1px solid rgba(255, 255, 255, 0.12);
    background: rgba(255, 255, 255, 0.06);
    color: var(--mat-sys-on-surface);
    font-size: 0.82rem;
    font-weight: 700;
    letter-spacing: 0.06em;
    text-transform: uppercase;
}

.account-dialog__status-pill--active {
    border-color: rgba(34, 197, 94, 0.3);
    background: rgba(34, 197, 94, 0.12);
    color: #2db36f;
}

.account-dialog__status-pill--trial {
    border-color: rgba(251, 191, 36, 0.28);
    background: rgba(245, 158, 11, 0.14);
    color: #d18b09;
}

.account-dialog__message,
.account-dialog__loading-copy {
    margin: 0;
    max-width: 60ch;
    color: var(--app-body-color, var(--mat-sys-on-surface));
}

.account-dialog__message {
    padding: 14px 16px;
    border-radius: 16px;
    border: 1px solid rgba(255, 255, 255, 0.08);
    background: rgba(255, 255, 255, 0.04);
    line-height: 1.55;
}

.account-dialog__hero-stats {
    display: grid;
    grid-template-columns: repeat(4, minmax(0, 1fr));
    gap: 12px;
}

.account-stat {
    position: relative;
    overflow: hidden;
    display: grid;
    gap: 8px;
    padding: 16px;
    border-radius: 18px;
    border: 1px solid rgba(255, 255, 255, 0.08);
    background:
        linear-gradient(
            180deg,
            rgba(255, 255, 255, 0.08),
            rgba(255, 255, 255, 0.02)
        ),
        var(--app-widget-bg, var(--mat-sys-surface-container));
    box-shadow: 0 14px 30px rgba(0, 0, 0, 0.12);
}

.account-stat__icon {
    width: 36px;
    height: 36px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 12px;
    background: rgba(99, 102, 241, 0.12);
    color: var(--app-provider-xtream, var(--mat-sys-primary));
}

.account-stat__label {
    color: var(--app-muted-color, var(--mat-sys-on-surface-variant));
    font-size: 0.76rem;
    font-weight: 700;
    letter-spacing: 0.1em;
    text-transform: uppercase;
}

.account-stat__value {
    font-size: clamp(1.45rem, 2vw, 1.95rem);
    font-weight: 700;
    letter-spacing: -0.04em;
    color: var(--app-heading-color, var(--mat-sys-on-surface));
}

.account-stat__meter {
    position: relative;
    overflow: hidden;
    height: 6px;
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.08);
}

.account-stat__meter span {
    display: block;
    height: 100%;
    border-radius: inherit;
    background: linear-gradient(90deg, #4f46e5, #06b6d4);
}

.account-dialog__content {
    margin: 0;
    padding: 24px 28px;
    background: var(--app-widget-bg, var(--mat-sys-surface));
}

.account-dialog__grid {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 18px;
}

.account-panel {
    display: grid;
    gap: 18px;
    padding: 22px;
    border-radius: 24px;
    border: 1px solid var(--app-separator);
    background:
        linear-gradient(
            180deg,
            rgba(255, 255, 255, 0.035),
            rgba(255, 255, 255, 0)
        ),
        var(--app-widget-bg, var(--mat-sys-surface-container-low));
    box-shadow: 0 20px 40px rgba(0, 0, 0, 0.08);
}

.account-panel__header {
    display: grid;
    gap: 6px;
}

.account-panel__header h3 {
    margin: 0;
    font-size: 1.3rem;
    font-weight: 650;
    letter-spacing: -0.03em;
}

.account-panel__eyebrow {
    margin: 0;
    color: var(--app-eyebrow-color, var(--mat-sys-on-surface-variant));
    font-size: 0.74rem;
    font-weight: 700;
    letter-spacing: 0.12em;
    text-transform: uppercase;
}

.account-detail-list {
    display: grid;
    gap: 10px;
    margin: 0;
}

.account-detail-row {
    display: grid;
    grid-template-columns: minmax(132px, 160px) minmax(0, 1fr);
    gap: 14px;
    align-items: baseline;
    padding: 12px 0;
    border-bottom: 1px solid rgba(255, 255, 255, 0.06);
}

.account-detail-row:last-child {
    border-bottom: 0;
    padding-bottom: 0;
}

.account-detail-row dt {
    margin: 0;
    color: var(--app-muted-color, var(--mat-sys-on-surface-variant));
    font-size: 0.76rem;
    font-weight: 700;
    letter-spacing: 0.1em;
    text-transform: uppercase;
}

.account-detail-row dd {
    margin: 0;
    color: var(--app-body-color, var(--mat-sys-on-surface));
    font-size: 0.98rem;
    font-weight: 560;
    word-break: break-word;
}

.account-detail-row__value--mono {
    font-family:
        'JetBrains Mono',
        'Roboto Mono',
        monospace;
    font-size: 0.9rem;
}

.account-detail-row__value--accent {
    color: var(--app-provider-xtream, var(--mat-sys-primary));
}

.account-detail-row__value--positive {
    color: #2db36f;
}

.account-detail-row__value--warning {
    color: #d18b09;
}

.account-chip-section {
    display: grid;
    gap: 12px;
}

.account-chip-section__label {
    margin: 0;
    color: var(--app-muted-color, var(--mat-sys-on-surface-variant));
    font-size: 0.76rem;
    font-weight: 700;
    letter-spacing: 0.1em;
    text-transform: uppercase;
}

.account-chip-group {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
}

.account-chip {
    display: inline-flex;
    align-items: center;
    min-height: 34px;
    padding: 0 12px;
    border-radius: 999px;
    border: 1px solid rgba(99, 102, 241, 0.16);
    background: rgba(99, 102, 241, 0.08);
    color: var(--mat-sys-on-surface);
    font-size: 0.86rem;
    font-weight: 600;
    text-transform: uppercase;
}

.account-chip--mono {
    font-family:
        'JetBrains Mono',
        'Roboto Mono',
        monospace;
    text-transform: none;
}

.account-chip--muted {
    border-color: rgba(255, 255, 255, 0.08);
    background: rgba(255, 255, 255, 0.04);
    color: var(--app-muted-color, var(--mat-sys-on-surface-variant));
}

.account-dialog__error-state {
    display: grid;
    justify-items: center;
    gap: 14px;
    padding: 44px 24px;
    border-radius: 24px;
    border: 1px dashed var(--app-separator);
    background:
        linear-gradient(
            180deg,
            rgba(255, 255, 255, 0.04),
            rgba(255, 255, 255, 0)
        ),
        var(--app-widget-bg, var(--mat-sys-surface-container-low));
    text-align: center;
}

.account-dialog__error-state h3,
.account-dialog__error-state p {
    margin: 0;
}

.account-dialog__error-state p {
    max-width: 52ch;
    color: var(--app-muted-color, var(--mat-sys-on-surface-variant));
    line-height: 1.55;
}

.account-dialog__error-icon {
    width: 56px;
    height: 56px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 18px;
    background: rgba(244, 63, 94, 0.12);
    color: var(--mat-sys-error);
}

.account-panel--loading {
    gap: 14px;
}

.account-skeleton {
    position: relative;
    overflow: hidden;
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.06);
}

.account-skeleton::after {
    content: '';
    position: absolute;
    inset: 0;
    transform: translateX(-100%);
    background: linear-gradient(
        90deg,
        transparent,
        rgba(255, 255, 255, 0.24),
        transparent
    );
    animation: account-dialog-shimmer 1.4s infinite;
}

.account-skeleton--stat {
    min-height: 126px;
    border-radius: 18px;
}

.account-skeleton--heading {
    width: 54%;
    height: 22px;
}

.account-skeleton--row {
    width: 100%;
    height: 18px;
}

.account-skeleton--row.short {
    width: 62%;
}

.account-dialog__actions {
    padding: 0 28px 24px;
    display: flex;
    justify-content: flex-end;
    gap: 12px;
    border-top: 1px solid var(--app-separator);
    background: var(--app-widget-bg, var(--mat-sys-surface));
}

.account-dialog__close {
    min-width: 120px;
    border-radius: 999px;
}

@keyframes account-dialog-shimmer {
    100% {
        transform: translateX(100%);
    }
}

@media (max-width: 980px) {
    .account-dialog__hero-stats,
    .account-dialog__grid {
        grid-template-columns: repeat(2, minmax(0, 1fr));
    }
}

@media (max-width: 720px) {
    .account-dialog__hero,
    .account-dialog__content,
    .account-dialog__actions {
        padding-left: 18px;
        padding-right: 18px;
    }

    .account-dialog__headline-row {
        flex-direction: column;
        align-items: flex-start;
    }

    .account-dialog__status-cluster {
        justify-content: flex-start;
    }

    .account-dialog__hero-stats,
    .account-dialog__grid {
        grid-template-columns: 1fr;
    }

    .account-detail-row {
        grid-template-columns: 1fr;
        gap: 6px;
    }
}

