1	@use 'sass:map';
2	@use '@angular/material' as mat;
3	@use 'styles';
4	
5	@include mat.elevation-classes();
6	@include mat.app-background();
7	
8	// ─── Typography ─────────────────────────────────────────────────────────────
9	$app-font-stack:
10	    "'DM Sans', 'Roboto', -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Helvetica Neue', Arial, sans-serif";
