12	$my-typography: mat.m2-define-typography-config(
13	    $font-family: $app-font-stack,
14	);
15	@include mat.typography-hierarchy($my-typography);
16	
17	// ─── M3 Themes ───────────────────────────────────────────────────────────────
18	$light-theme: mat.define-theme(
19	    (
20	        color: (
21	            theme-type: light,
22	            primary: mat.$violet-palette,
23	            tertiary: mat.$cyan-palette,
24	        ),
25	        typography: (
26	            plain-family: $app-font-stack,
27	            brand-family: $app-font-stack,
28	        ),
29	    )
30	);
31	
32	$dark-theme: mat.define-theme(
33	    (
