1	@use '../../styles/skeleton';
2	
3	// ─── Card base ───────────────────────────────────────────────────────────────
4	mat-card {
5	    overflow: hidden;
6	    transition:
7	        transform 0.18s ease,
8	        box-shadow 0.18s ease;
9	    box-shadow: none;
10	    background: transparent;
11	}
12	
13	mat-card:hover {
14	    transform: translateY(-3px);
15	    box-shadow: 0 6px 16px rgba(0, 0, 0, 0.12);
16	}
17	
18	// ─── Grid layout ─────────────────────────────────────────────────────────────
19	.grid {
20	    mat-card {
21	        cursor: pointer;
22	        width: 100%;
23	
24	        mat-card-content {
25	            padding: 0;
26	            margin: 0;
27	        }
28	
29	        .card-thumbnail-container {
30	            position: relative;
31	            width: 100%;
32	            border-radius: 10px;
33	            overflow: hidden;
34	            aspect-ratio: 2 / 3; // maintain poster ratio
35	            background: var(--mat-sys-surface-container-high);
36	        }
37	
38	        .stream-icon {
39	            width: 100%;
40	            height: 100%;
41	            object-fit: cover;
42	            border-radius: 10px;
43	            display: block;
44	            // No hardcoded light bg — uses parent container bg
45	            background: transparent;
46	        }
47	
48	        .stream-icon-placeholder {
49	            width: 100%;
50	            height: 100%;
51	            min-height: 200px;
52	            // Use graphite surface token, not hardcoded grey
53	            background: var(--mat-sys-surface-container-high);
54	            display: flex;
55	            flex-direction: column;
56	            justify-content: center;
57	            align-items: center;
58	            gap: 8px;
59	            color: var(--app-muted-color, var(--mat-sys-on-surface-variant));
60	            border-radius: 10px;
61	
62	            &::after {
63	                content: 'No cover';
64	                font-size: 0.75rem;
65	                font-weight: 500;
66	                letter-spacing: 0.03em;
67	            }
68	        }
69	
70	        .title {
71	            margin-top: 8px;
72	            padding: 0 2px;
73	            word-break: break-word;
74	            text-align: center;
75	            display: -webkit-box;
76	            -webkit-line-clamp: 2;
77	            -webkit-box-orient: vertical;
78	            overflow: hidden;
79	            font-size: 0.8rem;
80	            line-height: 1.35;
81	            color: var(--app-body-color, var(--mat-sys-on-surface-variant));
82	        }
83	    }
84	}
85	
86	// ─── Rating badge ─────────────────────────────────────────────────────────────
87	.rating {
88	    position: absolute;
89	    top: 6px;
90	    right: 6px;
91	    // Use a solid or highly opaque dark pill to avoid expensive backdrop-filter
92	    background: rgba(0, 0, 0, 0.85);
93	    color: #4ade80; // green-400, readable across themes
94	    font-size: 0.72rem;
95	    font-weight: 600;
96	    border-radius: 6px;
97	    display: flex;
98	    justify-content: center;
99	    align-items: center;
