.account-stat__label {
    color: var(--app-muted-color, var(--mat-sys-on-surface-variant));
    font-size: 0.72rem;
    font-weight: 600;
    letter-spacing: 0.1em;
    text-transform: uppercase;
}

.account-stat__value {
    font-size: 1.3rem;
    font-weight: 650;
    letter-spacing: -0.03em;
