}

.account-stat__meter {
    position: relative;
    overflow: hidden;
    height: 4px;
    border-radius: 999px;
    background: var(--app-separator);
}

.account-stat__meter span {
    display: block;
    height: 100%;
    border-radius: inherit;
    background: var(--app-provider-xtream, var(--mat-sys-primary));
}

