    animation: account-dialog-shimmer 1.4s infinite;
}

.account-skeleton--stat {
    min-height: 126px;
    border-radius: 18px;
}

.account-skeleton--heading {
    width: 54%;
    height: 22px;
}

.account-skeleton--row {
    width: 100%;
    height: 18px;
}

.account-skeleton--row.short {
    width: 62%;
}

.account-dialog__actions {
    padding: 0 28px 24px;
    display: flex;
    justify-content: flex-end;
    gap: 12px;
    border-top: 1px solid var(--app-separator);
    background: var(--app-widget-bg, var(--mat-sys-surface));
}

.account-dialog__close {
    min-width: 120px;
    border-radius: 999px;
}

@keyframes account-dialog-shimmer {
    100% {
        transform: translateX(100%);
    }
}

@media (max-width: 980px) {
    .account-dialog__hero-stats,
    .account-dialog__grid {
        grid-template-columns: repeat(2, minmax(0, 1fr));
    }
}

@media (max-width: 720px) {
    .account-dialog__hero,
    .account-dialog__content,
    .account-dialog__actions {
        padding-left: 18px;
        padding-right: 18px;
    }

    .account-dialog__headline-row {
        flex-direction: column;
        align-items: flex-start;
    }

    .account-dialog__status-cluster {
        justify-content: flex-start;
    }

    .account-dialog__hero-stats,
    .account-dialog__grid {
        grid-template-columns: 1fr;
    }

    .account-detail-row {
        grid-template-columns: 1fr;
        gap: 6px;
    }
}

