import { PlaylistInfoComponent } from '@iptvnator/playlist/shared/ui';
import {
    PlaylistContextFacade,
    PlaylistRefreshActionService,
} from '@iptvnator/playlist/shared/util';
import {
    buildPortalRailLinks,
    PORTAL_EXTERNAL_PLAYBACK,
    PortalRailLink,
