        }

        return Boolean(
            playlist.serverUrl || playlist.url || playlist.filePath
        );
    }

    refresh(playlist: PlaylistMeta): void {
        if (this.isRefreshing()) {
            return;
        }

        if (playlist.serverUrl) {
            this.refreshXtream(playlist);
